{
  "name": "WealthFlow Finance",
  "description": "A comprehensive personal finance dashboard for tracking transactions, managing investment portfolios, and setting budgets with interactive visualizations.",
  "requestFramePermissions": []
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export type TransactionType = 'income' | 'expense';

export interface Transaction {
  id: string;
  type: TransactionType;
  amount: number;
  category: string;
  date: string;
  description: string;
  paymentMethod: string;
  tags?: string[];
  createdAt: string;
}

export type InvestmentType = 'stock' | 'mutual_fund' | 'etf' | 'bond' | 'crypto';

export interface Investment {
  id: string;
  type: InvestmentType;
  name: string;
  symbol: string;
  quantity: number;
  buyPrice: number;
  buyDate: string;
  currentPrice: number;
  broker: string;
  notes?: string;
}

export interface InvestmentTransaction {
  id: string;
  investmentId: string;
  transactionType: 'buy' | 'sell';
  quantity: number;
  price: number;
  date: string;
  totalAmount: number;
  profitLoss?: number;
}

export interface BudgetCategory {
  category: string;
  budgetAmount: number;
  spentAmount: number;
}

export interface Budget {
  id: string;
  name: string;
  startDate: string;
  endDate: string;
  categories: BudgetCategory[];
}

export interface UserSettings {
  currency: string;
  darkMode: boolean;
  name: string;
}

export const INCOME_CATEGORIES = [
  'Salary', 'Freelance', 'Dividends', 'Interest', 'Gift', 'Refund', 'Other Income'
];

export const EXPENSE_CATEGORIES = [
  'Food', 'Transport', 'Shopping', 'Bills', 'Entertainment', 'Healthcare', 'Housing', 'Education', 'Travel', 'Insurance', 'Other'
];

export const PAYMENT_METHODS = [
  'Cash', 'Credit Card', 'Debit Card', 'UPI', 'Bank Transfer', 'Mobile Wallet'
];

export const INVESTMENT_TYPES = [
  { value: 'stock', label: 'Stocks' },
  { value: 'mutual_fund', label: 'Mutual Funds' },
  { value: 'etf', label: 'ETFs' },
  { value: 'bond', label: 'Bonds' },
  { value: 'crypto', label: 'Cryptocurrency' }
];

export const CURRENCIES = [
  { code: 'USD', symbol: '$' },
  { code: 'EUR', symbol: '€' },
  { code: 'GBP', symbol: '£' },
  { code: 'INR', symbol: '₹' },
  { code: 'JPY', symbol: '¥' }
];

export const MOCK_TRANSACTIONS = [
  { id: '1', type: 'income', amount: 5000, category: 'Salary', date: '2023-10-01', description: 'Monthly paycheck', paymentMethod: 'Bank Transfer', createdAt: '2023-10-01' },
  { id: '2', type: 'expense', amount: 150, category: 'Food', date: '2023-10-02', description: 'Grocery shopping', paymentMethod: 'Credit Card', createdAt: '2023-10-02' },
  { id: '3', type: 'expense', amount: 45, category: 'Transport', date: '2023-10-03', description: 'Gas refill', paymentMethod: 'Debit Card', createdAt: '2023-10-03' },
  { id: '4', type: 'expense', amount: 800, category: 'Housing', date: '2023-10-05', description: 'Monthly Rent', paymentMethod: 'Bank Transfer', createdAt: '2023-10-05' },
];

import React, { useState, useEffect, useMemo, createContext, useContext } from 'react';
import { HashRouter, Routes, Route, Link, useLocation } from 'react-router-dom';
import { 
  LayoutDashboard, 
  ArrowLeftRight, 
  TrendingUp, 
  PieChart, 
  Settings, 
  Menu, 
  X, 
  Wallet,
  Plus,
  LogOut,
  ChevronRight,
  User,
  Bell,
  Search,
  Download,
  Filter
} from 'lucide-react';
import { 
  Transaction, 
  Investment, 
  InvestmentTransaction, 
  Budget, 
  UserSettings 
} from './types';
import Dashboard from './pages/Dashboard';
import TransactionsPage from './pages/TransactionsPage';
import InvestmentsPage from './pages/InvestmentsPage';
import BudgetPage from './pages/BudgetPage';
import SettingsPage from './pages/SettingsPage';
import ReportsPage from './pages/ReportsPage';

// Context for global state
interface AppState {
  transactions: Transaction[];
  investments: Investment[];
  investmentHistory: InvestmentTransaction[];
  budgets: Budget[];
  settings: UserSettings;
  addTransaction: (t: Omit<Transaction, 'id' | 'createdAt'>) => void;
  deleteTransaction: (id: string) => void;
  addInvestment: (i: Omit<Investment, 'id'>) => void;
  sellInvestment: (id: string, qty: number, price: number) => void;
  addBudget: (b: Omit<Budget, 'id'>) => void;
  updateSettings: (s: UserSettings) => void;
}

const AppContext = createContext<AppState | undefined>(undefined);

export const useAppState = () => {
  const context = useContext(AppContext);
  if (!context) throw new Error('useAppState must be used within AppProvider');
  return context;
};

const AppProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('wf_transactions');
    return saved ? JSON.parse(saved) : [];
  });
  const [investments, setInvestments] = useState<Investment[]>(() => {
    const saved = localStorage.getItem('wf_investments');
    return saved ? JSON.parse(saved) : [];
  });
  const [investmentHistory, setInvestmentHistory] = useState<InvestmentTransaction[]>(() => {
    const saved = localStorage.getItem('wf_inv_history');
    return saved ? JSON.parse(saved) : [];
  });
  const [budgets, setBudgets] = useState<Budget[]>(() => {
    const saved = localStorage.getItem('wf_budgets');
    return saved ? JSON.parse(saved) : [];
  });
  const [settings, setSettings] = useState<UserSettings>(() => {
    const saved = localStorage.getItem('wf_settings');
    return saved ? JSON.parse(saved) : { currency: 'USD', darkMode: false, name: 'John Doe' };
  });

  useEffect(() => {
    localStorage.setItem('wf_transactions', JSON.stringify(transactions));
    localStorage.setItem('wf_investments', JSON.stringify(investments));
    localStorage.setItem('wf_inv_history', JSON.stringify(investmentHistory));
    localStorage.setItem('wf_budgets', JSON.stringify(budgets));
    localStorage.setItem('wf_settings', JSON.stringify(settings));
  }, [transactions, investments, investmentHistory, budgets, settings]);

  const addTransaction = (t: Omit<Transaction, 'id' | 'createdAt'>) => {
    const newTransaction: Transaction = {
      ...t,
      id: crypto.randomUUID(),
      createdAt: new Date().toISOString()
    };
    setTransactions(prev => [newTransaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    setTransactions(prev => prev.filter(t => t.id !== id));
  };

  const addInvestment = (i: Omit<Investment, 'id'>) => {
    const newInv: Investment = { ...i, id: crypto.randomUUID() };
    setInvestments(prev => [...prev, newInv]);

    const hist: InvestmentTransaction = {
      id: crypto.randomUUID(),
      investmentId: newInv.id,
      transactionType: 'buy',
      quantity: i.quantity,
      price: i.buyPrice,
      date: i.buyDate,
      totalAmount: i.quantity * i.buyPrice
    };
    setInvestmentHistory(prev => [hist, ...prev]);
  };

  const sellInvestment = (id: string, qty: number, price: number) => {
    setInvestments(prev => prev.map(inv => {
      if (inv.id === id) {
        return { ...inv, quantity: inv.quantity - qty };
      }
      return inv;
    }).filter(inv => inv.quantity > 0));

    const hist: InvestmentTransaction = {
      id: crypto.randomUUID(),
      investmentId: id,
      transactionType: 'sell',
      quantity: qty,
      price: price,
      date: new Date().toISOString().split('T')[0],
      totalAmount: qty * price
    };
    setInvestmentHistory(prev => [hist, ...prev]);
  };

  const addBudget = (b: Omit<Budget, 'id'>) => {
    setBudgets(prev => [{ ...b, id: crypto.randomUUID() }, ...prev]);
  };

  const updateSettings = (s: UserSettings) => setSettings(s);

  const value = {
    transactions,
    investments,
    investmentHistory,
    budgets,
    settings,
    addTransaction,
    deleteTransaction,
    addInvestment,
    sellInvestment,
    addBudget,
    updateSettings
  };

  return <AppContext.Provider value={value}>{children}</AppContext.Provider>;
};

const SidebarItem = ({ icon: Icon, label, path, active }: { icon: any, label: string, path: string, active: boolean }) => (
  <Link 
    to={path} 
    className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-200 ${
      active 
        ? 'bg-white/10 text-white font-semibold' 
        : 'text-indigo-100 hover:bg-white/5 hover:text-white'
    }`}
  >
    <Icon size={20} />
    <span>{label}</span>
  </Link>
);

const AppLayout = () => {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const location = useLocation();
  const { settings } = useAppState();

  const navItems = [
    { icon: LayoutDashboard, label: 'Dashboard', path: '/' },
    { icon: ArrowLeftRight, label: 'Transactions', path: '/transactions' },
    { icon: TrendingUp, label: 'Investments', path: '/investments' },
    { icon: PieChart, label: 'Budgets', path: '/budgets' },
    { icon: Bell, label: 'Reports', path: '/reports' },
    { icon: Settings, label: 'Settings', path: '/settings' },
  ];

  return (
    <div className={`flex min-h-screen bg-gray-50 ${settings.darkMode ? 'dark' : ''}`}>
      {/* Sidebar Overlay */}
      {sidebarOpen && (
        <div 
          className="fixed inset-0 bg-black/50 z-40 lg:hidden" 
          onClick={() => setSidebarOpen(false)}
        />
      )}

      {/* Sidebar */}
      <aside className={`fixed inset-y-0 left-0 w-64 bg-primary-gradient text-white transform transition-transform duration-300 ease-in-out z-50 lg:translate-x-0 lg:static ${sidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="flex flex-col h-full">
          <div className="p-6 flex items-center gap-3">
            <div className="bg-white/20 p-2 rounded-xl">
              <Wallet size={24} className="text-white" />
            </div>
            <h1 className="text-xl font-bold tracking-tight">WealthFlow</h1>
          </div>

          <nav className="flex-1 px-4 mt-4 space-y-1">
            {navItems.map((item) => (
              <SidebarItem 
                key={item.path} 
                {...item} 
                active={location.pathname === item.path}
              />
            ))}
          </nav>

          <div className="p-4 border-t border-white/10">
            <button className="flex items-center gap-3 w-full px-4 py-3 text-indigo-100 hover:text-white transition-colors">
              <LogOut size={20} />
              <span>Log Out</span>
            </button>
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col min-w-0 h-screen overflow-hidden">
        {/* Header */}
        <header className="h-16 bg-white border-b flex items-center justify-between px-6 shrink-0 z-30">
          <div className="flex items-center gap-4">
            <button 
              className="lg:hidden p-2 hover:bg-gray-100 rounded-lg" 
              onClick={() => setSidebarOpen(true)}
            >
              <Menu size={24} />
            </button>
            <div className="hidden sm:flex items-center bg-gray-100 rounded-full px-4 py-2 gap-2 text-gray-500 focus-within:ring-2 focus-within:ring-indigo-500 transition-all">
              <Search size={18} />
              <input 
                type="text" 
                placeholder="Search transactions..." 
                className="bg-transparent border-none focus:outline-none text-sm w-48"
              />
            </div>
          </div>

          <div className="flex items-center gap-3 sm:gap-6">
            <button className="p-2 text-gray-500 hover:text-indigo-600 hover:bg-indigo-50 rounded-full transition-all relative">
              <Bell size={20} />
              <span className="absolute top-2 right-2 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
            </button>
            <div className="flex items-center gap-3 pl-4 border-l">
              <div className="text-right hidden sm:block">
                <p className="text-sm font-semibold">{settings.name}</p>
                <p className="text-xs text-gray-500">Premium Account</p>
              </div>
              <div className="w-10 h-10 rounded-full bg-indigo-100 border-2 border-white flex items-center justify-center text-indigo-700 font-bold overflow-hidden">
                <img src={`https://picsum.photos/seed/${settings.name}/100/100`} alt="Avatar" />
              </div>
            </div>
          </div>
        </header>

        {/* Page Area */}
        <div className="flex-1 overflow-y-auto p-4 sm:p-8 bg-gray-50">
          <Routes>
            <Route path="/" element={<Dashboard />} />
            <Route path="/transactions" element={<TransactionsPage />} />
            <Route path="/investments" element={<InvestmentsPage />} />
            <Route path="/budgets" element={<BudgetPage />} />
            <Route path="/reports" element={<ReportsPage />} />
            <Route path="/settings" element={<SettingsPage />} />
          </Routes>
        </div>
      </main>
    </div>
  );
};

export default function App() {
  return (
    <AppProvider>
      <HashRouter>
        <AppLayout />
      </HashRouter>
    </AppProvider>
  );
}

import React, { useMemo } from 'react';
import { useAppState } from '../App';
import { 
  BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer, 
  AreaChart, Area, PieChart as RePieChart, Pie, Cell, Legend 
} from 'recharts';
import { 
  ArrowUpRight, ArrowDownRight, TrendingUp, DollarSign, Wallet, 
  Plus, MoreVertical, CreditCard, ShoppingBag, Utensils, Home
} from 'lucide-react';
import { Link } from 'react-router-dom';

const StatCard = ({ title, amount, change, icon: Icon, colorClass, prefix = '$' }: any) => (
  <div className="bg-white p-6 rounded-2xl shadow-sm border border-gray-100 flex flex-col">
    <div className="flex items-center justify-between mb-4">
      <div className={`p-3 rounded-xl ${colorClass}`}>
        <Icon size={24} className="text-white" />
      </div>
      <button className="text-gray-400 hover:text-gray-600">
        <MoreVertical size={20} />
      </button>
    </div>
    <div>
      <p className="text-gray-500 text-sm font-medium mb-1">{title}</p>
      <h3 className="text-2xl font-bold tracking-tight">{prefix}{amount.toLocaleString()}</h3>
      <div className="mt-2 flex items-center gap-1">
        {change >= 0 ? (
          <span className="text-green-500 text-xs font-semibold flex items-center">
            <ArrowUpRight size={14} /> +{change}%
          </span>
        ) : (
          <span className="text-red-500 text-xs font-semibold flex items-center">
            <ArrowDownRight size={14} /> {change}%
          </span>
        )}
        <span className="text-gray-400 text-xs">from last month</span>
      </div>
    </div>
  </div>
);

const Dashboard = () => {
  const { transactions, investments, settings } = useAppState();

  const stats = useMemo(() => {
    const totalIncome = transactions.filter(t => t.type === 'income').reduce((acc, t) => acc + t.amount, 0);
    const totalExpense = transactions.filter(t => t.type === 'expense').reduce((acc, t) => acc + t.amount, 0);
    const portfolioValue = investments.reduce((acc, inv) => acc + (inv.quantity * inv.currentPrice), 0);
    const netWorth = (totalIncome - totalExpense) + portfolioValue;

    return { totalIncome, totalExpense, portfolioValue, netWorth };
  }, [transactions, investments]);

  const chartData = useMemo(() => {
    // Generate simple monthly data for demo
    const months = ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun'];
    return months.map(m => ({
      name: m,
      income: Math.floor(Math.random() * 5000) + 3000,
      expense: Math.floor(Math.random() * 3000) + 1000,
    }));
  }, []);

  const categoryData = useMemo(() => {
    const categories: Record<string, number> = {};
    transactions.filter(t => t.type === 'expense').forEach(t => {
      categories[t.category] = (categories[t.category] || 0) + t.amount;
    });
    return Object.entries(categories).map(([name, value]) => ({ name, value }));
  }, [transactions]);

  const COLORS = ['#6366f1', '#a855f7', '#ec4899', '#f59e0b', '#10b981', '#3b82f6'];

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Financial Overview</h2>
          <p className="text-gray-500">Welcome back, {settings.name}! Here's what's happening with your money.</p>
        </div>
        <div className="flex items-center gap-3">
          <Link to="/transactions" className="flex items-center gap-2 bg-white border border-gray-200 text-gray-700 px-4 py-2 rounded-xl text-sm font-semibold hover:bg-gray-50 transition-all shadow-sm">
            Manage
          </Link>
          <button className="flex items-center gap-2 bg-indigo-600 text-white px-4 py-2 rounded-xl text-sm font-semibold hover:bg-indigo-700 transition-all shadow-md shadow-indigo-100">
            <Plus size={18} />
            <span>Add Transaction</span>
          </button>
        </div>
      </div>

      {/* Stats Grid */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-6">
        <StatCard title="Net Worth" amount={stats.netWorth} change={12.5} icon={Wallet} colorClass="bg-indigo-600" />
        <StatCard title="Income" amount={stats.totalIncome} change={8.2} icon={ArrowUpRight} colorClass="bg-green-500" />
        <StatCard title="Expenses" amount={stats.totalExpense} change={-2.4} icon={ArrowDownRight} colorClass="bg-red-500" />
        <StatCard title="Portfolio" amount={stats.portfolioValue} change={5.1} icon={TrendingUp} colorClass="bg-purple-600" />
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Main Chart */}
        <div className="lg:col-span-2 bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <div className="flex items-center justify-between mb-8">
            <h3 className="font-bold text-lg">Cash Flow</h3>
            <div className="flex items-center gap-4 text-xs font-medium">
              <div className="flex items-center gap-1.5"><span className="w-3 h-3 bg-indigo-500 rounded-full"></span> Income</div>
              <div className="flex items-center gap-1.5"><span className="w-3 h-3 bg-purple-400 rounded-full"></span> Expenses</div>
            </div>
          </div>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <AreaChart data={chartData}>
                <defs>
                  <linearGradient id="colorIncome" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#6366f1" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#6366f1" stopOpacity={0}/>
                  </linearGradient>
                  <linearGradient id="colorExpense" x1="0" y1="0" x2="0" y2="1">
                    <stop offset="5%" stopColor="#a855f7" stopOpacity={0.1}/>
                    <stop offset="95%" stopColor="#a855f7" stopOpacity={0}/>
                  </linearGradient>
                </defs>
                <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                <XAxis dataKey="name" axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} dy={10} />
                <YAxis axisLine={false} tickLine={false} tick={{fill: '#94a3b8', fontSize: 12}} />
                <Tooltip 
                  contentStyle={{borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0,0,0,0.1)'}}
                  cursor={{stroke: '#e2e8f0', strokeWidth: 2}}
                />
                <Area type="monotone" dataKey="income" stroke="#6366f1" strokeWidth={3} fillOpacity={1} fill="url(#colorIncome)" />
                <Area type="monotone" dataKey="expense" stroke="#a855f7" strokeWidth={3} fillOpacity={1} fill="url(#colorExpense)" />
              </AreaChart>
            </ResponsiveContainer>
          </div>
        </div>

        {/* Expenses Breakdown */}
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <h3 className="font-bold text-lg mb-8">Expense Breakdown</h3>
          <div className="h-[250px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <RePieChart>
                <Pie
                  data={categoryData.length > 0 ? categoryData : [{name: 'No Data', value: 1}]}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                  {categoryData.length === 0 && <Cell fill="#f1f5f9" />}
                </Pie>
                <Tooltip />
                <Legend iconType="circle" />
              </RePieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-6 space-y-4">
            {categoryData.slice(0, 3).map((cat, idx) => (
              <div key={cat.name} className="flex items-center justify-between">
                <div className="flex items-center gap-3">
                  <div className="w-2 h-2 rounded-full" style={{ backgroundColor: COLORS[idx % COLORS.length] }}></div>
                  <span className="text-sm font-medium text-gray-600">{cat.name}</span>
                </div>
                <span className="text-sm font-bold">${cat.value.toLocaleString()}</span>
              </div>
            ))}
          </div>
        </div>
      </div>

      {/* Recent Transactions */}
      <div className="bg-white rounded-2xl border border-gray-100 shadow-sm overflow-hidden">
        <div className="p-6 flex items-center justify-between border-b border-gray-50">
          <h3 className="font-bold text-lg">Recent Transactions</h3>
          <Link to="/transactions" className="text-sm font-semibold text-indigo-600 hover:text-indigo-700">View All</Link>
        </div>
        <div className="overflow-x-auto">
          <table className="w-full text-left">
            <thead>
              <tr className="bg-gray-50/50 text-gray-500 text-xs font-semibold uppercase tracking-wider">
                <th className="px-6 py-4">Transaction</th>
                <th className="px-6 py-4">Date</th>
                <th className="px-6 py-4">Category</th>
                <th className="px-6 py-4">Method</th>
                <th className="px-6 py-4 text-right">Amount</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {transactions.slice(0, 5).map((t) => (
                <tr key={t.id} className="hover:bg-gray-50/50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-3">
                      <div className={`w-9 h-9 rounded-full flex items-center justify-center ${t.type === 'income' ? 'bg-green-100 text-green-600' : 'bg-red-100 text-red-600'}`}>
                        {t.type === 'income' ? <ArrowUpRight size={18} /> : <ArrowDownRight size={18} />}
                      </div>
                      <span className="text-sm font-semibold">{t.description}</span>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-500">{t.date}</td>
                  <td className="px-6 py-4">
                    <span className="px-2.5 py-1 rounded-full text-xs font-medium bg-gray-100 text-gray-600">{t.category}</span>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-500">{t.paymentMethod}</td>
                  <td className={`px-6 py-4 text-sm font-bold text-right ${t.type === 'income' ? 'text-green-600' : 'text-red-600'}`}>
                    {t.type === 'income' ? '+' : '-'}${t.amount.toLocaleString()}
                  </td>
                </tr>
              ))}
              {transactions.length === 0 && (
                <tr>
                  <td colSpan={5} className="px-6 py-12 text-center text-gray-500 italic">No transactions found. Add your first one above!</td>
                </tr>
              )}
            </tbody>
          </table>
        </div>
      </div>
    </div>
  );
};

