                      </div>
                      <div>
                        <p className="text-sm font-bold text-gray-900">{t.description}</p>
                        <p className="text-xs text-gray-400 capitalize">{t.type}</p>
                      </div>
                    </div>
                  </td>
                  <td className="px-6 py-4 text-sm text-gray-600">{t.date}</td>
                  <td className="px-6 py-4">
