import React, { useState, useMemo } from 'react';
import { useAppState } from '../App';
import { Plus, TrendingUp, TrendingDown, DollarSign, PieChart as PieChartIcon, Activity, PlusCircle, MinusCircle, MoreHorizontal } from 'lucide-react';
import { INVESTMENT_TYPES } from '../constants';
import { ResponsiveContainer, PieChart, Pie, Cell, Tooltip, Legend } from 'recharts';

const InvestmentCard = ({ investment, onSell }: { investment: any, onSell: (id: string) => void }) => {
  const investedAmount = investment.quantity * investment.buyPrice;
  const currentTotal = investment.quantity * investment.currentPrice;
  const pnl = currentTotal - investedAmount;
  const pnlPercent = (pnl / investedAmount) * 100;
  const isPositive = pnl >= 0;

  return (
    <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className="w-12 h-12 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
            <Activity size={24} />
          </div>
          <div>
            <h4 className="font-bold text-gray-900">{investment.name}</h4>
            <p className="text-xs text-gray-400 font-medium uppercase tracking-wider">{investment.symbol} • {investment.type.replace('_', ' ')}</p>
          </div>
        </div>
        <div className="flex gap-2">
          <button onClick={() => onSell(investment.id)} className="p-2 text-gray-400 hover:text-red-600 hover:bg-red-50 rounded-lg transition-colors">
            <MinusCircle size={20} />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-2 gap-4 mt-6">
        <div>
          <p className="text-xs text-gray-500 font-medium mb-1">Quantity</p>
          <p className="text-lg font-bold">{investment.quantity}</p>
        </div>
        <div>
          <p className="text-xs text-gray-500 font-medium mb-1">Current Value</p>
          <p className="text-lg font-bold">${currentTotal.toLocaleString()}</p>
        </div>
      </div>

      <div className="mt-6 pt-6 border-t border-gray-50 flex items-center justify-between">
        <div className="space-y-1">
          <p className="text-xs text-gray-400 font-medium">Avg. Buy Price</p>
          <p className="text-sm font-semibold">${investment.buyPrice.toLocaleString()}</p>
        </div>
        <div className="text-right space-y-1">
          <p className="text-xs text-gray-400 font-medium">Total Returns</p>
          <p className={`text-sm font-bold flex items-center justify-end gap-1 ${isPositive ? 'text-green-500' : 'text-red-500'}`}>
            {isPositive ? <TrendingUp size={14} /> : <TrendingDown size={14} />}
            {isPositive ? '+' : ''}{pnlPercent.toFixed(2)}%
          </p>
        </div>
      </div>
    </div>
  );
};

const InvestmentsPage = () => {
  const { investments, investmentHistory, addInvestment, sellInvestment } = useAppState();
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Summary calculations
  const summary = useMemo(() => {
    let totalValue = 0;
    let totalInvested = 0;
    investments.forEach(inv => {
      totalValue += inv.quantity * inv.currentPrice;
      totalInvested += inv.quantity * inv.buyPrice;
    });
    const totalPnl = totalValue - totalInvested;
    const pnlPercent = totalInvested > 0 ? (totalPnl / totalInvested) * 100 : 0;
    return { totalValue, totalInvested, totalPnl, pnlPercent };
  }, [investments]);

  // Allocation data
  const allocationData = useMemo(() => {
    const types: Record<string, number> = {};
    investments.forEach(inv => {
      const label = inv.type.replace('_', ' ').toUpperCase();
      types[label] = (types[label] || 0) + (inv.quantity * inv.currentPrice);
    });
    return Object.entries(types).map(([name, value]) => ({ name, value }));
  }, [investments]);

  const COLORS = ['#6366f1', '#a855f7', '#ec4899', '#f59e0b', '#10b981', '#3b82f6'];

  const handleSell = (id: string) => {
    const inv = investments.find(i => i.id === id);
    if (!inv) return;
    const qtyStr = prompt(`Enter quantity to sell (Max: ${inv.quantity})`, inv.quantity.toString());
    const qty = parseFloat(qtyStr || '0');
    if (qty > 0 && qty <= inv.quantity) {
      sellInvestment(id, qty, inv.currentPrice);
    }
  };

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Investment Portfolio</h2>
          <p className="text-gray-500">Monitor your assets and track performance over time.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
