        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-gray-500 text-sm font-medium mb-1">Total Value</p>
          <h3 className="text-2xl font-bold">${summary.totalValue.toLocaleString()}</h3>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-gray-500 text-sm font-medium mb-1">Total Invested</p>
          <h3 className="text-2xl font-bold">${summary.totalInvested.toLocaleString()}</h3>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-gray-500 text-sm font-medium mb-1">Total Profit/Loss</p>
          <h3 className={`text-2xl font-bold ${summary.totalPnl >= 0 ? 'text-green-500' : 'text-red-500'}`}>
            {summary.totalPnl >= 0 ? '+' : ''}${Math.abs(summary.totalPnl).toLocaleString()}
          </h3>
        </div>
        <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm">
          <p className="text-gray-500 text-sm font-medium mb-1">ROI %</p>
          <div className="flex items-center gap-2">
            <h3 className={`text-2xl font-bold ${summary.pnlPercent >= 0 ? 'text-green-500' : 'text-red-500'}`}>
              {summary.pnlPercent >= 0 ? '+' : ''}{summary.pnlPercent.toFixed(2)}%
            </h3>
            {summary.pnlPercent >= 0 ? <TrendingUp className="text-green-500" size={24} /> : <TrendingDown className="text-red-500" size={24} />}
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        <div className="lg:col-span-1 bg-white p-8 rounded-2xl border border-gray-100 shadow-sm flex flex-col items-center">
          <h3 className="font-bold text-lg self-start mb-6">Asset Allocation</h3>
          <div className="w-full h-[250px]">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={allocationData.length > 0 ? allocationData : [{name: 'No Assets', value: 1}]}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={85}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {allocationData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                  {allocationData.length === 0 && <Cell fill="#f1f5f9" />}
                </Pie>
                <Tooltip formatter={(value: number) => `$${value.toLocaleString()}`} />
                <Legend layout="horizontal" align="center" verticalAlign="bottom" iconType="circle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="lg:col-span-2 grid grid-cols-1 md:grid-cols-2 gap-6">
          {investments.map(inv => (
            <InvestmentCard key={inv.id} investment={inv} onSell={handleSell} />
          ))}
          {investments.length === 0 && (
            <div className="col-span-full bg-white border border-dashed border-gray-200 rounded-2xl p-12 flex flex-col items-center justify-center text-gray-400">
              <Activity size={48} className="mb-4 opacity-20" />
