              </tr>
            </thead>
            <tbody className="divide-y divide-gray-50">
              {investmentHistory.map((h) => {
                const inv = investments.find(i => i.id === h.investmentId);
                return (
                  <tr key={h.id} className="hover:bg-gray-50/50 transition-colors">
