import React, { useMemo, useState } from 'react';
import { useAppState } from '../App';
import { Plus, Target, AlertTriangle, CheckCircle2, MoreHorizontal, ShoppingCart, Utensils, Car, Lightbulb } from 'lucide-react';
import { EXPENSE_CATEGORIES } from '../constants';

const BudgetCard = ({ category, spent, limit }: { category: string, spent: number, limit: number }) => {
  const percent = Math.min((spent / limit) * 100, 100);
  const remaining = limit - spent;
  const isOver = spent > limit;
  const isApproaching = percent > 80 && !isOver;

  let color = 'bg-green-500';
  let textColor = 'text-green-600';
  let bgColor = 'bg-green-50';

  if (isOver) {
    color = 'bg-red-500';
    textColor = 'text-red-600';
    bgColor = 'bg-red-50';
  } else if (isApproaching) {
    color = 'bg-amber-500';
    textColor = 'text-amber-600';
    bgColor = 'bg-amber-50';
  }

  return (
    <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-xl ${bgColor} ${textColor} flex items-center justify-center`}>
            {isOver ? <AlertTriangle size={20} /> : <Target size={20} />}
          </div>
          <h4 className="font-bold">{category}</h4>
        </div>
        <button className="text-gray-400">
          <MoreHorizontal size={20} />
        </button>
      </div>

      <div className="flex items-end justify-between mb-2">
        <p className="text-sm font-medium text-gray-500">
          Spent <span className="text-gray-900 font-bold">${spent.toLocaleString()}</span> of ${limit.toLocaleString()}
        </p>
        <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${bgColor} ${textColor}`}>
          {Math.round(percent)}%
        </span>
      </div>

      <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
        <div 
          className={`h-full transition-all duration-500 ${color}`} 
          style={{ width: `${percent}%` }}
        ></div>
      </div>

      <div className="mt-4 flex items-center justify-between">
        <p className="text-xs text-gray-400">
          {isOver ? (
            <span className="text-red-500 font-bold">Over budget by ${Math.abs(remaining).toLocaleString()}</span>
          ) : (
            <span>${remaining.toLocaleString()} left to spend</span>
          )}
        </p>
        {isOver && <AlertTriangle size={14} className="text-red-500" />}
        {!isOver && percent >= 100 && <CheckCircle2 size={14} className="text-green-500" />}
      </div>
    </div>
  );
};

const BudgetPage = () => {
