const InvestmentCard = ({ investment, onSell }: { investment: any, onSell: (id: string) => void, key?: any }) => {
  const investedAmount = investment.quantity * investment.buyPrice;
  const currentTotal = investment.quantity * investment.currentPrice;
  const pnl = currentTotal - investedAmount;
  const pnlPercent = (pnl / investedAmount) * 100;
  const isPositive = pnl >= 0;

  return (
    <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm hover:shadow-md transition-shadow">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
