        </div>
      </div>
    </div>
  );
};

const InvestmentsPage = () => {
  const { investments, investmentHistory, addInvestment, sellInvestment } = useAppState();
  const [isModalOpen, setIsModalOpen] = useState(false);

  // Summary calculations
  const summary = useMemo(() => {
    let totalValue = 0;
    let totalInvested = 0;
    investments.forEach(inv => {
      totalValue += inv.quantity * inv.currentPrice;
      totalInvested += inv.quantity * inv.buyPrice;
    });
    const totalPnl = totalValue - totalInvested;
    const pnlPercent = totalInvested > 0 ? (totalPnl / totalInvested) * 100 : 0;
    return { totalValue, totalInvested, totalPnl, pnlPercent };
  }, [investments]);

  // Allocation data
  const allocationData = useMemo(() => {
    const types: Record<string, number> = {};
    investments.forEach(inv => {
      const label = inv.type.replace('_', ' ').toUpperCase();
      types[label] = (types[label] || 0) + (inv.quantity * inv.currentPrice);
    });
    return Object.entries(types).map(([name, value]) => ({ name, value }));
  }, [investments]);

  const COLORS = ['#6366f1', '#a855f7', '#ec4899', '#f59e0b', '#10b981', '#3b82f6'];

  const handleSell = (id: string) => {
    const inv = investments.find(i => i.id === id);
    if (!inv) return;
    const qtyStr = prompt(`Enter quantity to sell (Max: ${inv.quantity})`, inv.quantity.toString());
    const qty = parseFloat(qtyStr || '0');
    if (qty > 0 && qty <= inv.quantity) {
      sellInvestment(id, qty, inv.currentPrice);
    }
