import React, { useMemo, useState } from 'react';
import { useAppState } from '../App';
import { Plus, Target, AlertTriangle, CheckCircle2, MoreHorizontal, ShoppingCart, Utensils, Car, Lightbulb } from 'lucide-react';
import { EXPENSE_CATEGORIES } from '../constants';

// Fix: Added key to props type to satisfy TS during JSX spread
const BudgetCard = ({ category, spent, limit }: { category: string, spent: number, limit: number, key?: any }) => {
  const percent = Math.min((spent / limit) * 100, 100);
  const remaining = limit - spent;
  const isOver = spent > limit;
  const isApproaching = percent > 80 && !isOver;

  let color = 'bg-green-500';
  let textColor = 'text-green-600';
  let bgColor = 'bg-green-50';

  if (isOver) {
    color = 'bg-red-500';
    textColor = 'text-red-600';
    bgColor = 'bg-red-50';
  } else if (isApproaching) {
    color = 'bg-amber-500';
    textColor = 'text-amber-600';
    bgColor = 'bg-amber-50';
  }

  return (
    <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm flex flex-col">
      <div className="flex items-center justify-between mb-4">
        <div className="flex items-center gap-3">
          <div className={`w-10 h-10 rounded-xl ${bgColor} ${textColor} flex items-center justify-center`}>
            {isOver ? <AlertTriangle size={20} /> : <Target size={20} />}
          </div>
          <h4 className="font-bold">{category}</h4>
        </div>
        <button className="text-gray-400">
          <MoreHorizontal size={20} />
        </button>
      </div>

      <div className="flex items-end justify-between mb-2">
        <p className="text-sm font-medium text-gray-500">
          Spent <span className="text-gray-900 font-bold">${spent.toLocaleString()}</span> of ${limit.toLocaleString()}
        </p>
        <span className={`text-xs font-bold px-2 py-0.5 rounded-full ${bgColor} ${textColor}`}>
          {Math.round(percent)}%
        </span>
      </div>

      <div className="w-full h-2.5 bg-gray-100 rounded-full overflow-hidden">
        <div 
          className={`h-full transition-all duration-500 ${color}`} 
          style={{ width: `${percent}%` }}
        ></div>
      </div>

      <div className="mt-4 flex items-center justify-between">
        <p className="text-xs text-gray-400">
          {isOver ? (
            <span className="text-red-500 font-bold">Over budget by ${Math.abs(remaining).toLocaleString()}</span>
          ) : (
            <span>${remaining.toLocaleString()} left to spend</span>
          )}
        </p>
        {isOver && <AlertTriangle size={14} className="text-red-500" />}
        {!isOver && percent >= 100 && <CheckCircle2 size={14} className="text-green-500" />}
      </div>
    </div>
  );
};

const BudgetPage = () => {
  const { transactions, budgets, addBudget } = useAppState();
  const [isModalOpen, setIsModalOpen] = useState(false);

  // For this simplified version, let's assume we use the first active budget or current month expenses
  const spentByCategory = useMemo(() => {
    const totals: Record<string, number> = {};
    const now = new Date();
    const currentMonth = now.getMonth();
    const currentYear = now.getFullYear();

    transactions.filter(t => {
      const d = new Date(t.date);
      return t.type === 'expense' && d.getMonth() === currentMonth && d.getFullYear() === currentYear;
    }).forEach(t => {
      totals[t.category] = (totals[t.category] || 0) + t.amount;
    });
    return totals;
  }, [transactions]);

  // Mock initial budget limits if none exist
  const displayBudgets = budgets.length > 0 ? budgets[0].categories : [
    { category: 'Food', budgetAmount: 500, spentAmount: spentByCategory['Food'] || 0 },
    { category: 'Transport', budgetAmount: 200, spentAmount: spentByCategory['Transport'] || 0 },
    { category: 'Shopping', budgetAmount: 300, spentAmount: spentByCategory['Shopping'] || 0 },
    { category: 'Entertainment', budgetAmount: 150, spentAmount: spentByCategory['Entertainment'] || 0 },
  ];

  const totals = useMemo(() => {
    const budgetTotal = displayBudgets.reduce((acc, b) => acc + b.budgetAmount, 0);
    const spentTotal = displayBudgets.reduce((acc, b) => acc + (spentByCategory[b.category] || 0), 0);
    return { budgetTotal, spentTotal };
  }, [displayBudgets, spentByCategory]);

  const overallPercent = Math.min((totals.spentTotal / totals.budgetTotal) * 100, 100);

  return (
    <div className="space-y-8">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight">Budgets</h2>
          <p className="text-gray-500">Set and track monthly spending targets by category.</p>
        </div>
        <button 
          onClick={() => setIsModalOpen(true)}
          className="flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2.5 rounded-xl text-sm font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100"
        >
          <Plus size={20} />
          <span>Set New Budget</span>
        </button>
      </div>

      {/* Overall Progress */}
      <div className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm">
        <div className="flex flex-col md:flex-row items-center gap-12">
          <div className="relative w-48 h-48 flex items-center justify-center">
             <svg className="w-full h-full transform -rotate-90">
                <circle 
                  cx="96" cy="96" r="80" 
                  className="stroke-gray-100" strokeWidth="16" fill="transparent" 
                />
                <circle 
                  cx="96" cy="96" r="80" 
                  className={`${overallPercent > 90 ? 'stroke-red-500' : 'stroke-indigo-500'} transition-all duration-1000 ease-out`} 
                  strokeWidth="16" fill="transparent"
                  strokeDasharray={2 * Math.PI * 80}
                  strokeDashoffset={2 * Math.PI * 80 * (1 - overallPercent / 100)}
                  strokeLinecap="round"
                />
             </svg>
             <div className="absolute inset-0 flex flex-col items-center justify-center">
                <span className="text-4xl font-bold">{Math.round(overallPercent)}%</span>
                <span className="text-xs text-gray-400 font-medium uppercase tracking-widest mt-1">Total Used</span>
             </div>
          </div>
          <div className="flex-1 space-y-6">
            <div>
              <h3 className="text-xl font-bold mb-1">Monthly Budget Status</h3>
              <p className="text-gray-500 text-sm">You have spent ${totals.spentTotal.toLocaleString()} out of your ${totals.budgetTotal.toLocaleString()} monthly allowance.</p>
            </div>
            <div className="grid grid-cols-2 gap-8">
              <div>
                <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Monthly Allowance</p>
                <p className="text-2xl font-bold">${totals.budgetTotal.toLocaleString()}</p>
              </div>
              <div>
                <p className="text-gray-400 text-xs font-bold uppercase tracking-wider mb-1">Remaining</p>
                <p className={`text-2xl font-bold ${totals.budgetTotal - totals.spentTotal < 0 ? 'text-red-500' : 'text-gray-900'}`}>
                  ${Math.max(0, totals.budgetTotal - totals.spentTotal).toLocaleString()}
                </p>
              </div>
            </div>
            <div className="flex items-center gap-2 text-sm">
              <span className={`px-3 py-1 rounded-full font-bold ${overallPercent > 90 ? 'bg-red-100 text-red-600' : 'bg-indigo-100 text-indigo-600'}`}>
                {overallPercent > 90 ? 'Caution: Near Limit' : 'On Track'}
              </span>
              <span className="text-gray-400">• Current cycle: Oct 1 - Oct 31</span>
            </div>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {displayBudgets.map(b => (
          <BudgetCard 
            key={b.category} 
            category={b.category} 
            limit={b.budgetAmount} 
            spent={spentByCategory[b.category] || 0} 
          />
        ))}
        {displayBudgets.length === 0 && (
          <div className="col-span-full py-12 text-center text-gray-500">No category budgets defined. Click "Set New Budget" to begin.</div>
        )}
      </div>

      {/* Simplified Modal Logic */}
      {isModalOpen && (
        <div className="fixed inset-0 bg-black/50 z-[100] flex items-center justify-center p-4">
          <div className="bg-white rounded-3xl w-full max-md shadow-2xl p-8">
            <h3 className="text-xl font-bold mb-6">Create New Budget Limit</h3>
            <div className="space-y-4">
              <div className="space-y-2">
                <label className="text-sm font-semibold">Category</label>
                <select id="b-cat" className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl">
                  {EXPENSE_CATEGORIES.map(c => <option key={c} value={c}>{c}</option>)}
                </select>
              </div>
              <div className="space-y-2">
                <label className="text-sm font-semibold">Monthly Limit</label>
                <input id="b-amt" type="number" placeholder="500.00" className="w-full px-4 py-3 bg-gray-50 border-none rounded-xl" />
              </div>
              <button 
                onClick={() => {
                  const cat = (document.getElementById('b-cat') as HTMLSelectElement).value;
                  const amt = parseFloat((document.getElementById('b-amt') as HTMLInputElement).value);
                  if (cat && amt > 0) {
                    addBudget({
                      name: 'Monthly Budget',
                      startDate: '2023-10-01',
                      endDate: '2023-10-31',
                      categories: [{ category: cat, budgetAmount: amt, spentAmount: 0 }]
                    });
                    setIsModalOpen(false);
                  }
                }}
                className="w-full py-4 bg-indigo-600 text-white rounded-2xl font-bold shadow-lg shadow-indigo-100 mt-4"
              >
                Set Limit
              </button>
              <button onClick={() => setIsModalOpen(false)} className="w-full py-2 text-gray-500 font-medium">Cancel</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default BudgetPage;

import React, { useState, useMemo } from 'react';
import { useAppState } from '../App';
import { GoogleGenAI, Type } from "@google/genai";
import { Sparkles, BrainCircuit, Lightbulb, Rocket, AlertCircle, RefreshCw, ChevronRight } from 'lucide-react';

const AIInsights = () => {
  const { transactions, investments, budgets, settings } = useAppState();
  const [loading, setLoading] = useState(false);
  const [insights, setInsights] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);

  const generateInsights = async () => {
    setLoading(true);
    setError(null);
    try {
      // Use process.env.API_KEY directly as required
      const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

      const financialSummary = {
        userName: settings.name,
        currency: settings.currency,
        totalTransactions: transactions.length,
        recentExpenses: transactions.filter(t => t.type === 'expense').slice(0, 10).map(t => ({ amount: t.amount, category: t.category, desc: t.description })),
        investmentCount: investments.length,
        totalInvested: investments.reduce((acc, i) => acc + (i.quantity * i.buyPrice), 0),
        portfolioValue: investments.reduce((acc, i) => acc + (i.quantity * i.currentPrice), 0),
        budgets: budgets.map(b => b.categories.map(c => ({ category: c.category, limit: c.budgetAmount }))).flat()
      };

      const prompt = `
        You are an elite AI Financial Advisor. Based on the user's data below, provide 3 actionable, highly specific financial insights or recommendations.

        User Data:
        ${JSON.stringify(financialSummary, null, 2)}
      `;

      // Upgraded to gemini-3-pro-preview for complex reasoning tasks and added responseSchema for reliability
      const response = await ai.models.generateContent({
        model: 'gemini-3-pro-preview',
        contents: prompt,
        config: {
          responseMimeType: "application/json",
          responseSchema: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { 
                  type: Type.STRING,
                  description: "The headline of the financial insight."
                },
                description: { 
                  type: Type.STRING,
                  description: "A concise and professional explanation of the recommendation."
                },
                iconType: { 
                  type: Type.STRING,
                  description: "One of: 'saving', 'investing', 'alert', 'growth'"
                }
              },
              required: ["title", "description", "iconType"],
              propertyOrdering: ["title", "description", "iconType"]
            },
          }
        }
      });

      // Directly access .text property as per guidelines
      setInsights(response.text || null);
    } catch (err: any) {
      console.error(err);
      setError("Failed to generate AI insights. Please check your network or try again.");
    } finally {
      setLoading(false);
    }
  };

  const parsedInsights = useMemo(() => {
    if (!insights) return [];
    try {
      return JSON.parse(insights);
    } catch (e) {
      return [];
    }
  }, [insights]);

  const getIcon = (type: string) => {
    switch (type) {
      case 'saving': return <Lightbulb className="text-amber-500" />;
      case 'investing': return <Rocket className="text-indigo-500" />;
      case 'alert': return <AlertCircle className="text-red-500" />;
      case 'growth': return <BrainCircuit className="text-emerald-500" />;
      default: return <Sparkles className="text-indigo-500" />;
    }
  };

  return (
    <div className="space-y-8 animate-in fade-in duration-500">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4">
        <div>
          <h2 className="text-2xl font-bold tracking-tight flex items-center gap-3">
            <Sparkles className="text-indigo-600" />
            AI Financial Insights
          </h2>
          <p className="text-gray-500">Intelligent analysis of your spending and investment patterns.</p>
        </div>
        <button 
          onClick={generateInsights}
          disabled={loading}
          className="flex items-center justify-center gap-2 bg-primary-gradient text-white px-6 py-3 rounded-2xl text-sm font-bold hover:scale-[1.02] transition-all shadow-lg shadow-indigo-200 disabled:opacity-50 disabled:scale-100"
        >
          {loading ? <RefreshCw size={20} className="animate-spin" /> : <Sparkles size={20} />}
          <span>{loading ? 'Analyzing Data...' : 'Generate New Insights'}</span>
        </button>
      </div>

      {!insights && !loading && !error && (
        <div className="bg-white rounded-3xl p-12 text-center border-2 border-dashed border-gray-100 max-w-2xl mx-auto flex flex-col items-center gap-6">
          <div className="w-20 h-20 bg-indigo-50 rounded-full flex items-center justify-center text-indigo-600">
            <BrainCircuit size={40} />
          </div>
          <div className="space-y-2">
            <h3 className="text-xl font-bold text-gray-900">Discover Hidden Trends</h3>
            <p className="text-gray-500">Click the button above to let WealthFlow AI analyze your finances and provide personalized growth tips.</p>
          </div>
        </div>
      )}

      {loading && (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {[1, 2, 3].map(i => (
            <div key={i} className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm animate-pulse space-y-4">
              <div className="w-12 h-12 bg-gray-100 rounded-xl"></div>
              <div className="h-4 bg-gray-100 rounded w-3/4"></div>
              <div className="h-4 bg-gray-100 rounded w-full"></div>
              <div className="h-4 bg-gray-100 rounded w-1/2"></div>
            </div>
          ))}
        </div>
      )}

      {error && (
        <div className="bg-red-50 text-red-600 p-6 rounded-2xl flex items-center gap-4 max-w-2xl mx-auto border border-red-100">
          <AlertCircle />
          <p className="font-medium">{error}</p>
        </div>
      )}

      {insights && !loading && (
        <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
          {parsedInsights.map((insight: any, idx: number) => (
            <div key={idx} className="bg-white p-8 rounded-3xl border border-gray-100 shadow-sm hover:shadow-md transition-all hover:border-indigo-200 group">
              <div className="w-14 h-14 bg-gray-50 rounded-2xl flex items-center justify-center mb-6 group-hover:scale-110 transition-transform">
                {getIcon(insight.iconType)}
              </div>
              <h3 className="text-lg font-bold mb-3 text-gray-900">{insight.title}</h3>
              <p className="text-gray-500 text-sm leading-relaxed mb-6">{insight.description}</p>
              <button className="text-indigo-600 text-xs font-bold flex items-center gap-1 group-hover:translate-x-1 transition-transform uppercase tracking-wider">
                Learn More <ChevronRight size={14} />
              </button>
            </div>
          ))}
        </div>
      )}

      {insights && !loading && (
        <div className="bg-primary-gradient p-8 rounded-3xl text-white relative overflow-hidden">
          <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
            <div className="space-y-2">
              <h3 className="text-xl font-bold">Deep Analysis Complete</h3>
              <p className="text-indigo-100 text-sm">Our AI has scanned {transactions.length} transactions and {investments.length} investment assets to provide these recommendations.</p>
            </div>
            <div className="bg-white/10 px-6 py-3 rounded-2xl border border-white/20 backdrop-blur-sm flex items-center gap-3">
              <Sparkles size={20} className="text-indigo-200" />
              <span className="text-sm font-semibold">Gemini 3 Pro Powered</span>
            </div>
          </div>
          <div className="absolute -right-24 -top-24 w-64 h-64 bg-white/10 rounded-full blur-3xl"></div>
        </div>
      )}
    </div>
  );
};

export default AIInsights;
